```

**4. Playwright Test (axe-core + Alfa, SC 1.4.1, SC 1.4.11, SC 2.4.7)**

`tests/e2e/alert-block.spec.ts`:
```ts
import { test, expect } from '@playwright/test';
import { AxeBuilder } from '@axe-core/playwright';
import { alfa } from '@siteimprove/alfa-playwright';

test('Alert block meets WCAG 2.2 AA', async ({ page }) => {
  await page.goto('https://agency.example.org/');

  // Ensure alert block is visible
  await expect(page.locator('[role="alert"]')).toBeVisible();

  // axe-core: focus-visible + contrast
  const axeResults = await new AxeBuilder({ page })
    .withTags(['wcag2aa'])
    .include('[role="alert"]')
    .disableRules(['color-contrast', 'tabindex']) // We manually inspect contrast
    .analyze();

  expect(axeResults.violations).toEqual([]);

  // Alfa: explicit contrast check
  const alertEl = await alfa(page).then(res => res.filter(r => r.target.isElement()).find(e => e.target.asElement().getAttribute('role') === 'alert'));
  const checks = await alertEl?.run([alfa.checks.ColorContrastAA, alfa.checks.FocusVisible]);

  expect(checks?.filter(c => c.outcome === 'fail')).toHaveLength(0);

  // Manual contrast check for background/foreground
  const style = await page.locator('[role="alert"]').getAttribute('style');
  expect(style).toMatch(/background-color:[^;]+; color:[^;]+/);
});
```

**Compliance Summary**
- ✅ SC 1.4.1 (Use of Color): color used *in addition to* position/shape (e.g., left border)
- ✅ SC 1.4.11 (Non-text Contrast): alert border ≥ 3:1, focus outline ≥ 2px
- ✅ SC 2.4.7 (Focus Visible): visible focus indicator on close button
- ✅ SC 4.1.2 (Name, Role, Value): `role="alert"`, `aria-live="assertive"`, close button has accessible name

Here's an end-to-end implementation for an accessible file download section in Drupal 11, covering configuration, Twig templating, Drush automation, and dual-engine accessibility testing:

**1. Content type & field configuration (Drupal UI)**
- Create *File Asset* content type with:
  - `field_file` (file, unrestricted types)
  - `field_file_size` (computed via `hook_preprocess_node`, see below)
  - `field_accessibility_status` (list: `accessible`, `not_accessible`, `unknown`)
  - `field_document_type` (list: `pdf`, `csv`, `docx`, `xlsx`)
- Use **Media module** for embedded documents (e.g., PDF viewer via `media_type: document`)

**2. Preprocess function to compute file size**
`my_module.module`:
```php
function my_module_preprocess_node__file_asset(array &$variables): void {
  $file = $variables['elements']['#node']->get('field_file')->entity;
  if ($file) {
    $size = format_size($file->getSize());
    $accessibility = $variables['elements']['#node']->get('field_accessibility_status')->value;
    $variables['file_metadata'] = [
      'size' => $size,
      'type' => $file->getMimeType(),
      'accessibility' => $accessibility,
      'is_accessible' => $accessibility === 'accessible',
    ];
  }
}
```

**3. Accessible Twig template**
`templates/node--file-asset.html.twig`:
```twig
{#
/**
 * @file
 * Theme implementation for file asset nodes.
 */
#}
<article{{ attributes }} aria-label="{{ content.field_title[0]['#context']['value'] }}">
  <header class="file-header">
    <h2 class="file-title">{{ content.field_title }}</h2>
    {% if file_metadata %}
      <p class="file-meta">
        {{ file_metadata.size }} • {{ file_metadata.type|replace({'application/': ''})|replace({'vnd.openxmlformats-officedocument': 'Office Open XML'}) }}
        {% if not file_metadata.is_accessible %}
          <span class="file-status" aria-label="This document may not be accessible to screen readers">⚠ Not fully accessible</span>
        {% endif %}
      </p>
    {% endif %}
  </header>

  <div class="file-actions">
    {% if node.field_file.0 %}
      {% set file_url = node.field_file.0.entity.url %}
      <a
        href="{{ file_url }}"
        aria-describedby="download-{{ node.id }}-info"
        class="file-link"
      >
        Download
      </a>
      <p id="download-{{ node.id }}-info" class="visually-hidden">
        File: {{ node.label.value }}.
        {{ file_metadata.size }}.
        {% if not file_metadata.is_accessible %}
          Warning: This file may contain barriers for people with disabilities.
        {% endif %}
      </p>
    {% endif %}
  </div>
</article>
```
**Key accessibility features:**
- `aria-label` on `<article>` (SC 4.1.2)
- `aria-describedby` links download button to expanded description (SC 1.3.1, 2.4.4)
- Visually-hidden status notice (SC 1.4.1, 1.4.3)

**4. Drush command for bulk accessibility audit**
`src/Drush/Commands/AccessibilityCommands.php`:
```php
#[CLI\Command(name: 'my-module:audit-files')]
public function auditFiles(): void {
  $nodes = $this->entityTypeManager->getStorage('node')->loadByProperties(['type' => 'file_asset']);
  foreach ($nodes as $node) {
    $file = $node->get('field_file')->entity;
    if ($file && $file->getMimeType() === 'application/pdf') {
      $this->logger()->warning(
        'PDF detected: %title (%file). Consider adding alt text and tagged PDF.',
        ['%title' => $node->label(), '%file' => $file->getFileUri()]
      );
    }
  }
  $this->io()->success('Audit complete. Check logs for PDFs.');
}
```
Run: `drush my-module:audit-files`

**5. Playwright test with dual-engine audit**
`tests/file-download.test.ts`:
```ts
import { test, expect } from '@playwright/test';
import AxeBuilder from '@axe-core/playwright';
import { alfa } from '@siteimprove/alfa-playwright';

test('File download links include programmatic metadata', async ({ page }) => {
  await page.goto('/files');

  // Check aria-describedby exists and points to visible element
  const downloadLink = page.locator('a.file-link').first();
  const descId = await downloadLink.getAttribute('aria-describedby');
  expect(descId).toBeTruthy();
  const descElement = page.locator(`#${descId}`);
  await expect(descElement).toBeVisible({ visible: false });

  // Verify status notice appears for non-accessible files
  const nonAccessible = page.locator('.file-status', { hasText: 'Not fully accessible' }).first();
  const isAccessible = await page.locator('article').first().getAttribute('aria-label');

  // Dual-engine audit
  const axeResults = await new AxeBuilder({ page })
    .withTags(['wcag2aa'])
    .include('article')
    .analyze();
  expect(axeResults.violations).toEqual([]);

  const alfaResults = await alfa.fromPage(page).run();
  expect(alfaResults.filter(r => r.outcome === 'Failed')).toHaveLength(0);
});
```

**WCAG SC citations:**
- **1.3.1 (Info and Relationships)** — metadata programmatically determinable via `aria-describedby`
- **2.4.4 (Link Purpose)** — download link + expanded description
- **4.1.2 (Name, Role, Value)** — semantic `<article>` with `aria-label`
- **1.4.1 (Use of Color)** — status notice not color-only
- **1.4.3 (Contrast — Minimum)** — status notice meets 4.5:1 contrast

