### 2. Accessible Modal Dialog (SC 1.3.1, 2.1.1, 2.4.7, 4.1.2)
**File:** `js/event-modal.js`
```js
document.addEventListener('click', function (e) {
  const toggle = e.target.closest('.event-details-toggle');
  if (!toggle) return;

  const modal = document.getElementById('event-modal');
  if (!modal) return;

  const eventTitle = toggle.dataset.title;
  const eventDate = toggle.dataset.date;
  const eventLocation = toggle.dataset.location;

  // Update modal content
  modal.querySelector('[data-slot="title"]').textContent = eventTitle;
  modal.querySelector('[data-slot="date"]').textContent = eventDate;
  modal.querySelector('[data-slot="location"]').textContent = eventLocation;

  // Toggle visibility and focus
  const isOpen = modal.getAttribute('aria-hidden') === 'false';
  if (isOpen) {
    modal.setAttribute('aria-hidden', 'true');
    modal.setAttribute('hidden', '');
    toggle.setAttribute('aria-expanded', 'false');
  } else {
    modal.removeAttribute('hidden');
    modal.setAttribute('aria-hidden', 'false');
    toggle.setAttribute('aria-expanded', 'true');
    // Move focus to modal close button (SC 2.1.1)
    modal.querySelector('.modal-close').focus();
  }
});
```

