namespace Drupal\subscription_form\Plugin\Field\FieldType;

use Drupal\core\Field\FieldItemBase;
use Drupal\core\Field\FieldItemInterface;
use Drupal\core\TypedData\DataDefinition;

/**
 * Plugin implementation of the 'subscription_type' field type.
 *
 * @FieldType(
 *   id = "subscription_type",
 *   label = @Translation("Subscription Type"),
 *   description = @Translation("Stores subscription preference."),
 *   default_widget = "subscription_select",
 *   default_formatter = "subscription_default"
 * )
 */
class SubscriptionType extends FieldItemBase implements FieldItemInterface {

  public static function propertyDefinitions(FieldStorageDefinitionInterface $field_definition) {
    $properties['type'] = DataDefinition::create('string')
      ->setLabel(t('Subscription type'))
      ->setRequired(TRUE);

    return $properties;
  }

  public static function schema(FieldStorageDefinitionInterface $field_definition) {
    return [
      'columns' => [
        'type' => [
          'type' => 'varchar',
          'length' => 255,
          'not null' => TRUE,
        ],
      ],
    ];
  }

  public function isEmpty() {
    $value = $this->get('type')->getValue();
    return $value === NULL || $value === '';
  }
}
