- `role="dialog"` + `aria-modal="true"` (SC 4.1.2)
- `aria-labelledby` points to visible `<h2>` (SC 4.1.2)
- Focusable close button with `aria-label` (SC 2.1.1)
- Skip-to-close-button logic in JS

### 3. **JavaScript: Focus Management**

```js
// modules/custom/accessible_modal/assets/js/accessible-modal.js
Drupal.behaviors.accessibleModal = {
  attach: function (context) {
    const triggers = document.querySelectorAll('.modal-trigger');
    const modals = document.querySelectorAll('.modal');

    triggers.forEach(trigger => {
      trigger.addEventListener('click', function (e) {
        e.preventDefault();
        const modalId = trigger.getAttribute('aria-controls');
        const modal = document.getElementById(modalId);
        modal.classList.remove('hidden');
        modal.querySelector('[data-close-modal]').focus();
      });
    });

    document.addEventListener('click', function (e) {
      if (e.target.dataset.closeModal) {
        modals.forEach(m => m.classList.add('hidden'));
        triggers.forEach(t => t.focus());
      }
    });
  }
};
```

### 4. **Drush: Rebuild caches & rebuild routes**

```bash
$ drush en accessible_modal -y
$ drush cr
$ drush routes:rebuild
```

### 5. **Playwright Test: Dual-Audit with Axe + Alfa**

```typescript
// e2e/modal-accessibility.spec.ts
import { test, expect } from '@playwright/test';
import { AxeBuilder } from '@axe-core/playwright';
import { alfa } from '@siteimprove/alfa-playwright';

test('Modal dialog meets SC 2.1.1, 2.4.7, and 4.1.2', async ({ page }) => {
  await page.goto('https://agency.example.org/');

  // Click modal trigger
  await page.click('.modal-trigger');

  // Wait for modal to be visible
  await expect(page.locator('#accessible-modal')).toBeVisible();

  // Focus is on close button (SC 2.4.7)
  await expect(page.locator('.modal-close-btn')).toBeFocused();

  // Axe-core: no violations for keyboard or ARIA
  const axeResults = await new AxeBuilder({ page })
    .include('#accessible-modal')
    .disableRules(['color-contrast', 'duplicate-id'])
    .analyze();

  expect(axeResults.violations.filter(v =>
    ['keyboard-tab', 'aria-valid-attr-value', 'aria-allowed-attr'].includes(v.id)
  )).toHaveLength(0);

  // Alfa: explicit checks for SC 2.1.1, 2.4.7, 4.1.2
  const alfaResults = await alfa(page).run();
  expect(alfaResults.filter(r =>
    ['T12', 'T14', 'T49'].includes(r.id) // T12: keyboard, T14: focus visible, T49: name/role/value
  )).toHaveLength(0);

  // Close modal with Escape key
  await page.keyboard.press('Escape');
  await expect(page.locator('#accessible-modal')).not.toBeVisible();
  await expect(page.locator('.modal-trigger')).toBeVisible();
});
```

### ✅ Compliance Summary:
