class AlertBannerCommands extends DrushCommands {

  /**
   * @var Connection
   */
  protected $database;

  /**
   * @var LoggerInterface
   */
  protected $logger;

  public function __construct(Connection $database, LoggerInterface $logger) {
    $this->database = $database;
    $this->logger = $logger;
  }

  /**
