     expect(metaId).toMatch(/^file-meta-/);
     const metaText = await page.getByRole('region', { hidden: false })
       .filter({ has: page.locator(`#${metaId}`) })
       .textContent();
     expect(metaText).toContain('PDF');
     expect(metaText).toContain('2\.4 MB');

     // 3. Verify plain-text fallback exists
