 *   help = @Translation("Renders a table with proper headers and scope attributes."),
 *   theme = "views_view_grid",
 *   display_types = {"normal"}
 * )
 */
class A11yTable extends StylePluginBase {

  protected function defineOptions() {
    $options = parent::defineOptions();
    $options['header'] = ['default' => []];
    return $options;
  }

  public function buildOptionsForm(&$form, FormStateInterface $form_state) {
    parent::buildOptionsForm($form, $form_state);
    $form['header'] = [
      '#type' => 'details',
      '#title' => t('Accessible Header Configuration'),
      '#open' => TRUE,
    ];
    // Add fields to select which columns get scope="col"
  }

  public function render() {
    $rows = [];
    $header = [];
    $headers = $this->renderZone('header');
    foreach ($headers as $field => $label) {
      $header[] = [
        'data' => $label,
        'scope' => 'col',
        'class' => ['table-header'],
      ];
    }

    foreach ($this->view->result as $row_index => $row) {
      $this->view->rowPlugin->setRowIndex($row_index);
      $rows[] = [
        'data' => $this->view->rowPlugin->render($row),
        'class' => ['view-row'],
      ];
      $this->view->rowPlugin->resetRowPlugin();
    }

    return [
      '#type' => 'table',
      '#attributes' => [
        'role' => 'table',
        'aria-label' => $this->view->getTitle() ?: t('Grants listing'),
      ],
      'header' => $header,
      'rows' => $rows,
    ];
  }
}
```

