         .setAttribute('aria-modal', 'true')
         .setAttribute('aria-labelledby', 'modal-title') }}>
     <h2 id="modal-title">Permit Application</h2>
     <button type="button" aria-label="Close dialog" class="modal-close">
       <span aria-hidden="true">×</span>
     </button>
     <div class="modal-content">
       {{ children }}
     </div>
   </div>
   ```
   - Use `aria-modal="true"` on the root container and proper labelling.

3. **JavaScript: Focus Management (SC 2.1.2 compliant)**
   - Use `drupalDialog` behavior with focus trap via `tabbable`:
     ```ts
     // assets/permit_dialog.js
     Drupal.behaviors.permitDialog = {
       attach(context) {
         const modal = context.querySelector('#permit-modal');
         if (!modal) return;

         const closeBtn = modal.querySelector('.modal-close');
         const focusable = tabbable(modal);

         // Open: move focus to first focusable element
         modal.addEventListener('open', () => {
           focusable[0]?.focus();
         });

         // Close: return focus to opener
         closeBtn?.addEventListener('click', () => {
           modal.classList.add('hidden');
           modal.setAttribute('aria-hidden', 'true');
           document.getElementById('open-permit-btn')?.focus();
         });

         // Keyboard: prevent trap beyond dialog (SC 2.1.2)
         modal.addEventListener('keydown', (e) => {
           if (e.key === 'Tab') {
             const first = focusable[0];
             const last = focusable[focusable.length - 1];
             if (e.shiftKey && document.activeElement === first) {
               e.preventDefault();
               last.focus();
             } else if (!e.shiftKey && document.activeElement === last) {
               e.preventDefault();
               first.focus();
             }
           }
         });
       }
     };
     ```
   - **Crucial**: Do *not* use `tabindex="-1"` or `tabindex="0"` on non-interactive elements — only on buttons, links, and form controls.

