<?php
use Drupal\Core\Color\HtmlColor;

$request = Drupal::requestStack()->getCurrentRequest();
$output = drupal_render(Drupal::service('renderer')->renderRoot(Drupal::service('plugin.manager.block')->getBlocks('main')));
