   ```php
   // drush/Commands/DeployAuditCommands.php
   namespace Drush\Commands;

   use Drupal\Core\Site\Settings;
   use Drupal\Core\Render\RenderCallbackHelper;
   use Drush\Commands\DrushCommands;
   use Psr\Log\LoggerInterface;
   use Symfony\Component\DependencyInjection\ContainerInterface;

   class DeployAuditCommands extends DrushCommands {
     private LoggerInterface $logger;

     public function __construct(LoggerInterface $logger) {
       $this->logger = $logger;
       parent::__construct();
     }

     /**
      * Deploy patch, rebuild caches, and clear Twig cache.
      *
      * @command deploy:audit
      * @aliases deploy-audit
      */
     public function audit(): void {
       $this->logger->notice('Clearing Twig cache…');
       \Drupal::service('twig.config')->set('cache', false);
       \Drupal::service('twig.config')->set('auto_reload', true);
       drush_invoke_process('@self', 'cache:clear', ['twig']);
n       $this->logger->notice('Twig cache cleared.');
       drush_invoke_process('@self', 'cache:rebuild', ['all']);
       $this->logger->notice('All caches rebuilt.');
     }
   }
