Add keyboard navigation support in a custom JS file:
```ts
// assets/js/events-grid.js
const grid = document.querySelector('[role="grid"]');
grid.addEventListener('keydown', (e) => {
  const focus = document.activeElement;
  const cell = focus.closest('[role="gridcell"]');
  if (!cell) return;

  const cells = Array.from(grid.querySelectorAll('[role="gridcell"]'));
  const idx = cells.indexOf(cell);

  switch (e.key) {
    case 'ArrowRight': e.preventDefault(); cells[idx + 1]?.focus(); break;
    case 'ArrowLeft':  e.preventDefault(); cells[idx - 1]?.focus(); break;
    case 'ArrowDown':  e.preventDefault(); cells[idx + 7]?.focus(); break;
    case 'ArrowUp':    e.preventDefault(); cells[idx - 7]?.focus(); break;
  }
});
```

