<?php

namespace Drush\Commands;

use Drupal\file\FileInterface;
use Drush\Commands\DrushCommands;
use Psr\Log\LoggerInterface;

class ResourceIndexRebuildCommands extends DrushCommands {
  protected $logger;

  public function __construct(LoggerInterface $logger) {
    $this->logger = $logger;
  }

  /**
   * Rebuild resource index and update file metadata.
   *
   * @command resources:index-rebuild
   * @aliases rir
   */
  public function rebuild(): void {
    $this->logger->info('Starting resource index rebuild.');

    // Load all files and ensure alt text exists
    $files = \Drupal::entityTypeManager()
      ->getStorage('file')
      ->loadMultiple();

    foreach ($files as $file) {
      $alt = $file->get('alt') ?? '';
      if (empty($alt)) {
        $file->set('alt', 'File: ' . $file->getFilename());
        $file->save();
      }
    }

    $this->logger->info('File metadata rebuild complete.');
    drush_drupal_cache_rebuild();
  }
}
