<?php

namespace Drupal\custom_block\Plugin\Block;

use Drupal\block\BlockBase;
use Drupal\Core\Form\FormStateInterface;

class AccessibleAlertBlock extends BlockBase {

  public function defaultConfiguration() {
    return parent::defaultConfiguration() + [
      'alert_type' => 'info',
      'message' => 'Default message',
    ];
  }

  public function blockForm($form, FormStateInterface $form_state) {
    $form['alert_type'] = [
      '#type' => 'select',
      '#title' => t('Alert type'),
      '#options' => ['info' => t('Info'), 'success' => t('Success'), 'warning' => t('Warning')],
      '#default_value' => $this->configuration['alert_type'],
    ];
    $form['message'] = [
      '#type' => 'textarea',
      '#title' => t('Message'),
      '#default_value' => $this->configuration['message'],
      '#required' => TRUE,
    ];
    return $form;
  }

  public function blockSubmit($form, FormStateInterface $form_state) {
    $this->configuration['alert_type'] = $form_state->getValue('alert_type');
    $this->configuration['message'] = $form_state->getValue('message');
  }

  public function build() {
    return [
      '#theme' => 'custom_block_alert',
      '#alert_type' => $this->configuration['alert_type'],
      '#message' => $this->configuration['message'],
      '#attributes' => [
        'role' => 'alert',
        'aria-live' => 'polite',
        'class' => ['alert', 'alert-' . $this->configuration['alert_type']],
      ],
    ];
  }
}
```
