  defaults:
    _controller: '\Drupal\policy_listing\Controller\PolicyBlockController::content'
    _title: 'Policy Documents'
  requirements:
    _permission: 'access content'
```

**3. Block Plugin (`src/Plugin/Block/PolicyBlock.php`)**
- Extends `BlockBase`
- Uses `#cache` with appropriate contexts (`user.permissions`, `route`)
- Returns render array with `#attributes` including landmark role
```php
<?php

namespace Drupal\policy_listing\Plugin\Block;

use Drupal\block\BlockBase;
use Drupal\Core\Block\BlockPluginInterface;

class PolicyBlock extends BlockBase {
  public function build() {
    $policies = $this->getRecentPolicies(5);

    return [
      '#theme' => 'policy_listing_block',
      '#policies' => $policies,
      '#cache' => [
        'contexts' => ['user.permissions'],
        'max-age' => 3600,
      ],
      '#attributes' => [
        'role' => 'region',
        'aria-label' => $this->t('Recent policy documents'),
      ],
    ];
  }

  protected function getRecentPolicies($limit = 5) {
    // Return entity query for 'policy' node type, sorted by changed DESC
    $query = \Drupal::entityTypeManager()
      ->getStorage('node')
      ->getQuery();
    $query->condition('status', TRUE)
      ->condition('type', 'policy')
      ->sort('changed', 'DESC')
      ->range(0, $limit);
    $nids = $query->execute();
    return \Drupal::entityTypeManager()->getStorage('node')->loadMultiple($nids);
  }
}
```

**4. Twig Template (`policy-listing-block.html.twig`)**
```twig
{# themes/custom/mytheme/templates/policy-listing-block.html.twig #}
