  <h2>{{ title }}</h2>
  {% if policies|length %}
    <nav aria-label="Policy documents" role="navigation">
      <ul class="policy-list">
        {% for policy in policies %}
          <li>
            <a href="{{ path('entity.node.canonical', {'node': policy.id}) }}">
              {{ policy.label }}
            </a>
            <time datetime="{{ policy.changed|date('c') }}">
              {{ policy.changed|format_date('short') }}
            </time>
          </li>
        {% endfor %}
      </ul>
    </nav>
  {% else %}
    <p> {{ 'No policies published yet.'|t }} </p>
  {% endif %}
</div>
```
→ Uses `aria-label` on `<nav>` (SC 4.1.2), `time` element (SC 1.3.1), and semantic `<nav>` landmark (SC 1.3.1).

