<?php

namespace Drupal\agency_events\Controller;

use Drupal\core\Controller\ControllerBase;
use Drupal\core\database\Connection;
use Symfony\Component\DependencyInjection\ContainerInterface;

class EventListController extends ControllerBase {
  protected Connection $database;

  public function __construct(Connection $database) {
    $this->database = $database;
  }

  public static function create(ContainerInterface $container) {
    return new static($container->get('database'));
  }

  public function view(): array {
    $events = $this->database->select('agency_events', 'e')
      ->fields('e', ['title', 'date', 'time', 'location', 'url'])
      ->orderBy('e.date', 'ASC')
      ->execute()
      ->fetchAll();

    $build['events'] = [
      '#type' => 'table',
      '#header' => [
        ['data' => $this->t('Event Name'), 'scope' => 'col'],
        ['data' => $this->t('Date & Time'), 'scope' => 'col'],
        ['data' => $this->t('Location'), 'scope' => 'col'],
        ['data' => $this->t('Action'), 'scope' => 'col'],
      ],
      '#rows' => array_map(function ($e) {
        return [
          ['data' => $e->title, 'headers' => 'event-name'],
          ['data' => $e->date . ' at ' . $e->time, 'headers' => 'event-time'],
          ['data' => $e->location, 'headers' => 'event-location'],
          [
            'data' => [
              '#type' => 'link',
              '#title' => $this->t('Register'),
              '#url' => $e->url,
              '#attributes' => [
                'class' => ['button', 'button--small'],
                'aria-label' => $this->t('Register for @title', ['@title' => $e->title]),
              ],
            ],
          ],
        ];
      }, $events),
      '#attributes' => [
        'id' => 'events-table',
        'role' => 'region',
        'aria-label' => $this->t('Upcoming public events'),
      ],
    ];

    // Add a skip link to form
    $build['#attached']['drupalSettings']['agencyEvents'] = [
      'formId' => 'event-registration-form',
    ];

    $build['#attached']['library'][] = 'agency_events/accessibility';

    return $build;
  }
}
```

