import { accessibility } from '@siteimprove/alfa-playwright';

test('event calendar nav meets WCAG 2.2 AA', async ({ page }) => {
  await page.goto('https://agency.example.org/events');

  // 1. Contrast check (SC 1.4.3)
  const navLinks = await page.locator('.menu--main a').all();
  for (const link of navLinks) {
    const contrast = await link.evaluate((el) => {
      return (el as HTMLElement).innerText.trim();
    });
    expect(await link.matchColor contrast(3.5)).toBe(true);
  }

  // 2. Landmark presence (SC 1.3.1)
  await expect(page.locator('nav[role="navigation"][aria-label]')).toBeVisible();

  // 3. Skip link functionality (SC 2.4.1, 2.4.9)
  await page.click('.skip-link');
  await expect(page.locator('#main-content')).toBeFocused();

  // 4. Dual-engine audit (SC 1.4.3, 2.4.4, 2.4.6)
  await new AxeBuilder({ page }).withTags(['wcag2a', 'wcag2aa']).analyze();
  await accessibility.analyze(page);
});
```

**WCAG SCs covered**:
- `1.3.1` (Info and Relationships) — semantic landmarks and heading structure
- `1.4.3` (Contrast Minimum) — ≥4.5:1 for normal text or ≥3:1 for 18px+/bold 14px+ (12px+ for *large scale* 18pt/24px)
- `2.4.1` (Bypass Blocks) — skip link present and functional
- `2.4.4` (Link Purpose) — link text descriptive in context
- `2.4.9` (Link Purpose) — link purpose programmatically determinable

**Deployment workflow**:
1. `drush config:import` to load block config  
2. `drush theme:rebuild` to apply Twig changes  
3. `npx playwright test --project=chromium` for pre-deploy CI gate  
4. `npx playwright test --ui` to visually verify skip-link jump

**Note**: 3.5:1 contrast passes only for *large scale* text (≥18pt/24px). If font is smaller (e.g., 14px), increase to ≥4.5:1. Always validate computed font size in devtools.

