```

**`src/Drush/Commands/MyEventsCommands.php`:**
```php
namespace Drupal\my_events\Drush\Commands;

use Drush\Commands\DrushCommands;

class MyEventsCommands extends DrushCommands {

  /**
   * Rebuild caches and clear Twig template cache after deploy.
   *
   * @command my-events:rebuild
   * @aliases mer
   */
  public function rebuild(): void {
    $this->output()->writeln('<info>Rebuilding caches…</info>');
    \Drupal::service('cache_tags.invalidator')->invalidateAll();
    \Drupal::service('theme.registry')->reset();
    $this->output()->writeln('<comment>Twig templates will be recompiled on next render.</comment>');
