use Drupal\Core\Field\FieldItemBase;
use Drupal\Core\Field\FieldItemInterface;
use Drupal\Core\Form\FormStateInterface;
use Drupal\Core\TypedData\DataDefinition;

class AccessibleDateRange extends FieldItemBase {
  public static function propertyDefinitions(FieldStorageDefinitionInterface $field_definition) {
    $properties['start'] = DataDefinition::create('datetime_iso8601')
      ->setLabel(t('Start date'))
      ->setRequired(TRUE);
    $properties['end'] = DataDefinition::create('datetime_iso8601')
      ->setLabel(t('End date'))
      ->setRequired(TRUE);
    return $properties;
  }

  public function formElement(FieldItemListInterface $items, $delta, array $element, array &$form_state, $form) {
    $element['#type'] = 'container';
    $element['#attributes']['role'] = 'group';
    $element['#attributes']['aria-labelledby'] = 'accessible-daterange-label';
    $element['start'] = [
      '#type' => 'datetime',
      '#title' => t('Start'),
      '#title_display' => 'invisible',
      '#required' => TRUE,
      '#attributes' => [
        'aria-label' => t('Start date'),
      ],
    ];
    $element['end'] = [
      '#type' => 'datetime',
      '#title' => t('End'),
      '#title_display' => 'invisible',
      '#required' => TRUE,
      '#attributes' => [
        'aria-label' => t('End date'),
      ],
    ];
    return $element;
  }
}
```

