```php
use Drush\Attributes as CLI;
use Drupal\Core\Entity\EntityTypeManagerInterface;
use Symfony\Component\DependencyInjection\ContainerInterface;
use Drush\Commands\DrushCommands;

class EventSyncCommands extends DrushCommands {
  public function __construct(private EntityTypeManagerInterface $entityTypeManager) {}

  #[CLI\Command(name: 'event:sync-recurring', aliases: ['event-sync'])]
  public function sync(): void {
    $storage = $this->entityTypeManager->getStorage('node');
    $recurring = $storage->loadByProperties(['type' => 'event', 'field_is_recurring' => TRUE]);
    foreach ($recurring as $node) {
      $this->processRecurringInstance($node);
    }
    $this->output()->success('Recurring event instances generated and cached.');
  }

  private function processRecurringInstance($node): void {
    // Logic to expand recurring rule (e.g., iCal RRULE)
  }
}
```

