<?php

namespace Drush\Commands;

use Drush\Commands\DrushCommands;
use Psr\Log\LoggerInterface;
use Drupal\Core\Site\Settings;
use Symfony\Component\DependencyInjection\ContainerInterface;

class AccessibilityRebuildCommands extends DrushCommands {
  protected $logger;

  public function __construct(LoggerInterface $logger) {
    $this->logger = $logger;
  }

  /**
   * Rebuild caches and clear a11y-related caches.
   *
   * @command accessibility:rebuild
   * @aliases a11y-rebuild
   */
  public function rebuild(): void {
    $this->logger->info('Rebuilding caches to ensure accessibility markup consistency.');
    $this->drush('cache:rebuild');
    $this->logger->info('Cache rebuild complete. Accessibility updates now live.');
  }
}
